// src/pages/DashboardHome.js
import React, { useEffect, useState, useCallback, useRef } from 'react';
import Charts from '../components/Charts';
import api from '../services/api';
import WebSocketService from '../services/WebSocketService';
import { MapContainer, TileLayer, Marker, Popup } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';

// Fix default Leaflet marker icons
import markerIcon2x from 'leaflet/dist/images/marker-icon-2x.png';
import markerIcon from 'leaflet/dist/images/marker-icon.png';
import markerShadow from 'leaflet/dist/images/marker-shadow.png';

delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconUrl: markerIcon,
  iconRetinaUrl: markerIcon2x,
  shadowUrl: markerShadow,
});

const DashboardHome = () => {
  const [vehicleStats, setVehicleStats] = useState({
    total: 4,
    active: 2,
    idle: 1,
    maintenance: 1,
  });
  const [vehicles, setVehicles] = useState([
    { id: 1, lat: 19.0760, lng: 72.8777, status: 'ACTIVE', speed: 45, driver: 'John Doe', fuel: 75 },
    { id: 2, lat: 18.5204, lng: 73.8567, status: 'IDLE', speed: 0, driver: 'Jane Smith', fuel: 90 },
    { id: 3, lat: 12.9716, lng: 77.5946, status: 'MAINTENANCE', speed: 0, driver: 'Mike Johnson', fuel: 60 },
  ]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [retryCount, setRetryCount] = useState(0);
  const wsConnectedRef = useRef(false);
  const maxRetries = 3;
  const [currentTime, setCurrentTime] = useState(new Date());

  const [performanceData] = useState({
    months: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],
    activeVehicles: [18, 22, 20, 24, 23, 25],
  });

  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentTime(new Date());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const calculateStats = useCallback((vehicleData) => ({
    total: vehicleData.length,
    active: vehicleData.filter(v => v.status === 'ACTIVE').length,
    idle: vehicleData.filter(v => v.status === 'IDLE').length,
    maintenance: vehicleData.filter(v => v.status === 'MAINTENANCE').length,
  }), []);

  const mapCenter = vehicles.length > 0
    ? [vehicles[0].lat || 20.5937, vehicles[0].lng || 78.9629]
    : [20.5937, 78.9629];

  const ErrorDisplay = ({ message, onRetry }) => (
    <div className="bg-red-50 border-l-4 border-red-400 rounded-xl p-6 mb-8 shadow-sm">
      <div className="flex items-center justify-between">
        <div className="flex items-center">
          <div className="w-10 h-10 bg-red-100 rounded-full flex items-center justify-center mr-4">
            <svg className="w-5 h-5 text-red-600" fill="currentColor" viewBox="0 0 20 20">
              <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
            </svg>
          </div>
          <div>
            <h4 className="text-red-800 font-semibold">Connection Error</h4>
            <p className="text-red-700 text-sm">{message}</p>
          </div>
        </div>
        {onRetry && (
          <button
            onClick={onRetry}
            className="bg-red-600 text-white px-6 py-2 rounded-lg text-sm font-medium hover:bg-red-700 transition-colors duration-200 shadow-sm"
          >
            Retry
          </button>
        )}
      </div>
    </div>
  );

  if (loading) {
    return (
      <div className="p-6">
        <div className="flex items-center justify-center py-20">
          <div className="text-center">
            <div className="relative mb-6">
              <div className="w-16 h-16 border-4 border-blue-200 border-t-blue-600 rounded-full animate-spin mx-auto"></div>
              <div className="absolute inset-0 w-16 h-16 border-4 border-transparent border-t-blue-300 rounded-full animate-spin mx-auto" style={{animationDelay: '0.15s'}}></div>
            </div>
            <h3 className="text-lg font-semibold text-gray-900 mb-2">Loading Dashboard</h3>
            <p className="text-gray-600">Fetching your fleet data...</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6">
      {/* Page Title */}
      <div className="mb-8">
        <div className="flex items-center justify-between">
          <div>
            <h2 className="text-3xl font-bold text-gray-900 mb-2">Dashboard Home</h2>
            <p className="text-gray-600">Real-time fleet monitoring and analytics</p>
          </div>
          <div className="flex items-center space-x-4">
            <div className="inline-flex items-center px-4 py-2 rounded-full text-sm font-medium bg-green-100 text-green-800 border border-green-200">
              <div className="w-2 h-2 rounded-full mr-2 animate-pulse bg-green-500"></div>
              System Online
            </div>
            <div className="text-sm text-gray-500 bg-white px-4 py-2 rounded-lg shadow-sm border flex items-center">
              <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              {currentTime.toLocaleTimeString()}
            </div>
          </div>
        </div>
      </div>

      {error && (
        <ErrorDisplay 
          message={error} 
          onRetry={retryCount < maxRetries ? () => {
            setError(null);
            setLoading(true);
          } : null}
        />
      )}

      {/* Stats Cards Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100 hover:shadow-lg transition-all duration-300 hover:scale-105">
          <div className="flex items-center justify-between">
            <div className="flex-1">
              <p className="text-sm font-medium text-gray-600 mb-2">Total Vehicles</p>
              <p className="text-3xl font-bold text-gray-900">{vehicleStats.total}</p>
              <p className="text-xs text-blue-600 mt-2 flex items-center">
                <div className="w-2 h-2 bg-blue-500 rounded-full mr-2"></div>
                Fleet size
              </p>
            </div>
            <div className="w-16 h-16 bg-blue-100 rounded-2xl flex items-center justify-center ml-4">
              <svg className="w-8 h-8 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
              </svg>
            </div>
          </div>
        </div>

        <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100 hover:shadow-lg transition-all duration-300 hover:scale-105">
          <div className="flex items-center justify-between">
            <div className="flex-1">
              <p className="text-sm font-medium text-gray-600 mb-2">Active Vehicles</p>
              <p className="text-3xl font-bold text-gray-900">{vehicleStats.active}</p>
              <p className="text-xs text-green-600 mt-2 flex items-center">
                <div className="w-2 h-2 bg-green-500 rounded-full mr-1 animate-pulse"></div>
                On the move
              </p>
            </div>
            <div className="w-14 h-14 bg-green-100 rounded-2xl flex items-center justify-center">
              <svg className="w-8 h-8 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
            </div>
          </div>
        </div>

        <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100 hover:shadow-lg transition-all duration-300 hover:scale-105">
          <div className="flex items-center justify-between">
            <div className="flex-1">
              <p className="text-sm font-medium text-gray-600 mb-2">Idle Vehicles</p>
              <p className="text-3xl font-bold text-gray-900">{vehicleStats.idle}</p>
              <p className="text-xs text-yellow-600 mt-2 flex items-center">
                <div className="w-2 h-2 bg-yellow-500 rounded-full mr-1"></div>
                Ready for dispatch
              </p>
            </div>
            <div className="w-14 h-14 bg-yellow-100 rounded-2xl flex items-center justify-center">
              <svg className="w-8 h-8 text-yellow-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </div>
          </div>
        </div>

        <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100 hover:shadow-lg transition-all duration-300 hover:scale-105">
          <div className="flex items-center justify-between">
            <div className="flex-1">
              <p className="text-sm font-medium text-gray-600 mb-2">Maintenance</p>
              <p className="text-3xl font-bold text-gray-900">{vehicleStats.maintenance}</p>
              <p className="text-xs text-red-600 mt-2 flex items-center">
                <div className="w-2 h-2 bg-red-500 rounded-full mr-1"></div>
                Needs attention
              </p>
            </div>
            <div className="w-14 h-14 bg-red-100 rounded-2xl flex items-center justify-center">
              <svg className="w-8 h-8 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-2.5L13.732 4c-.77-.833-1.996-.833-2.464 0L3.34 16.5c-.77.833.192 2.5 1.732 2.5z" />
              </svg>
            </div>
          </div>
        </div>
      </div>

      {/* Fleet Performance Bar Chart and Map */}
      <div className="grid grid-cols-1 xl:grid-cols-2 gap-8 mb-8">
        <div className="bg-white rounded-2xl p-8 shadow-sm border border-gray-100 hover:shadow-lg transition-shadow duration-300">
          <div className="flex items-center justify-between mb-6">
            <div>
              <h3 className="text-xl font-bold text-gray-900">Fleet Performance Trends</h3>
              <p className="text-sm text-gray-600">Monthly active vehicle count over time</p>
            </div>
            <div className="flex items-center space-x-2">
              <div className="w-2 h-2 bg-blue-500 rounded-full animate-pulse"></div>
              <span className="text-sm text-gray-600 font-medium">6 Months</span>
            </div>
          </div>
          <div className="h-80">
            <Charts
              type="bar"
              data={{
                labels: performanceData.months,
                datasets: [
                  {
                    label: 'Active Vehicles',
                    data: performanceData.activeVehicles,
                    backgroundColor: 'rgba(59, 130, 246, 0.8)',
                    borderColor: 'rgb(59, 130, 246)',
                    borderWidth: 1,
                    borderRadius: 4,
                    borderSkipped: false,
                  },
                ],
              }}
              options={{
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                  legend: {
                    display: false,
                  },
                },
                scales: {
                  y: {
                    beginAtZero: true,
                    max: 30,
                  },
                },
              }}
            />
          </div>
        </div>

        <div className="bg-white rounded-2xl p-8 shadow-sm border border-gray-100 hover:shadow-lg transition-shadow duration-300">
          {/* Map details same as before */}
          {/* ...Use your current Map component code here */}
        </div>
      </div>

      {/* Recent Activities Section */}
      <div className="bg-white rounded-2xl p-8 shadow-sm border border-gray-100">
        <div className="flex items-center justify-between mb-6">
          <div>
            <h3 className="text-xl font-bold text-gray-900">Fleet Activity</h3>
            <p className="text-sm text-gray-600">Recent fleet events and notifications</p>
          </div>
          <button className="bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-blue-700 transition-colors">
            View All
          </button>
        </div>
        {/* Populate this section as needed */}
      </div>
    </div>
  );
};

export default DashboardHome;
